sys_hub_flow.snapshot:
{
  "trigger": {
    "type": "record_created",
    "table": "u_borrow_request",
    "condition": "u_status=requested"
  },
  "actions": [
    {
      "order": 100,
      "name": "Ask For Approval",
      "type": "core.approval.ask_for_approval",
      "inputs": {
        "table": "u_borrow_request",
        "approver": "librarian",
        "approval_field": "u_status"
      },
      "outputs": {
        "approval_result": "string (approved|rejected)"
      }
    },
    {
      "order": 200,
      "name": "Decision - Approved?",
      "type": "core.flow_logic.decision",
      "condition": "approval_result == 'approved'",
      "on_true": "goto:300",
      "on_false": "goto:500"
    },
    {
      "order": 300,
      "name": "Update Book",
      "type": "core.record.update",
      "inputs": {
        "table": "u_book",
        "record": "{{trigger.record.u_book}}",
        "fields": {
          "u_status": "issued"
        }
      }
    },
    {
      "order": 400,
      "name": "Update Borrow Request",
      "type": "core.record.update",
      "inputs": {
        "table": "u_borrow_request",
        "record": "{{trigger.record}}",
        "fields": {
          "u_status": "approved"
        }
      }
    },
    {
      "order": 410,
      "name": "Send Email - Approved",
      "type": "core.notification.send_email",
      "inputs": {
        "to": "{{trigger.record.u_requested_by}}",
        "subject": "Borrow Request Approved",
        "body": "Your borrow request for {{trigger.record.u_book.u_title}} has been approved. Please collect it from the library."
      },
      "goto": "end"
    },
    {
      "order": 500,
      "name": "Reject Request",
      "type": "core.record.update",
      "inputs": {
        "table": "u_borrow_request",
        "record": "{{trigger.record}}",
        "fields": {
          "u_status": "rejected"
        }
      }
    },
    {
      "order": 510,
      "name": "Send Email - Rejected",
      "type": "core.notification.send_email",
      "inputs": {
        "to": "{{trigger.record.u_requested_by}}",
        "subject": "Borrow Request Rejected",
        "body": "Your borrow request for {{trigger.record.u_book.u_title}} was not approved by the librarian."
      },
      "goto": "end"
    }
  ]
}
